import{_ as e,o as a,c as i,ae as r}from"./chunks/framework.CY_fclge.js";const u=JSON.parse('{"title":"Kernel Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"kernel/Benchmarks.md","filePath":"kernel/Benchmarks.md"}'),l={name:"kernel/Benchmarks.md"};function d(s,t,n,o,h,c){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="kernel-benchmarks" tabindex="-1">Kernel Benchmarks <a class="header-anchor" href="#kernel-benchmarks" aria-label="Permalink to &quot;Kernel Benchmarks&quot;">​</a></h1><h2 id="benchmark-overview" tabindex="-1">Benchmark Overview <a class="header-anchor" href="#benchmark-overview" aria-label="Permalink to &quot;Benchmark Overview&quot;">​</a></h2><p>This suite validates a single systems claim:</p><ul><li>Public-path recomputation should be bounded by dependency complexity (<code>k</code>), not dataset size (<code>n</code>).</li><li>Secret-path overhead must be measurable, bounded, and continuously improved without changing DSL semantics.</li></ul><h2 id="benchmark-matrix" tabindex="-1">Benchmark Matrix <a class="header-anchor" href="#benchmark-matrix" aria-label="Permalink to &quot;Benchmark Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>File</th><th>What It Proves</th></tr></thead><tbody><tr><td>#5 Sustained Mutation</td><td><code>tests/Benchmarks/benchmark.5.sustained-mutation.test.ts</code></td><td>Throughput stability over long mutation streams; p95 drift over time windows.</td></tr><tr><td>#6 Fan-Out Sensitivity</td><td><code>tests/Benchmarks/benchmark.6.fanout-sensitivity.test.ts</code></td><td>Latency behavior as fan-out grows, with constant derivation complexity <code>k</code>.</td></tr><tr><td>#7 Cold vs Warm</td><td><code>tests/Benchmarks/benchmark.7.cold-warm-profiles.test.ts</code></td><td>Separation of cold setup cost vs warm and steady-state runtime.</td></tr><tr><td>#8 Explain Overhead</td><td><code>tests/Benchmarks/benchmark.8.explain-overhead.test.ts</code></td><td>Observability overhead of <code>explain(path)</code> vs baseline mutation/read loops.</td></tr><tr><td>#9 Secret-Scope Impact</td><td><code>tests/Benchmarks/benchmark.9.secret-scope-impact.test.ts</code></td><td>Public vs secret latency envelope under equivalent workloads.</td></tr><tr><td>#10 Push vs Pull</td><td><code>tests/Benchmarks/benchmark.10.push-vs-pull.test.ts</code></td><td>Isolation of write-only (<code>push</code>) and first-read-after-write (<code>pull</code>) in eager vs lazy modes.</td></tr><tr><td>#11 Secret Push vs Pull</td><td><code>tests/Benchmarks/benchmark.11.secret-push-vs-pull.test.ts</code></td><td>Secret/public split of push vs pull; confirms secret-path cost structure after chunking/cache refactors.</td></tr><tr><td>Regression Gate</td><td><code>tests/Benchmarks/benchmark.regression-gate.test.ts</code></td><td>CI pass/fail checks for p95 latency, <code>k</code> complexity bound, and stealth masking correctness.</td></tr></tbody></table><h2 id="latest-verified-local-runs" tabindex="-1">Latest Verified Local Runs <a class="header-anchor" href="#latest-verified-local-runs" aria-label="Permalink to &quot;Latest Verified Local Runs&quot;">​</a></h2><p>Machine: <code>Suis-MacBook-Air</code><br> Run context: isolated local runs on <code>April 9, 2026</code></p><p>Notes:</p><ul><li>The tables below were taken from isolated runs on the current branch.</li><li><code>#9</code> and <code>#11</code> are the most sensitive to ambient machine load, so they should be read as performance envelopes, not hard SLAs.</li><li>The historical pre-5.4/5.5 secret baseline still lives in <code>tests/Benchmarks/BASELINE-5-FINAL.md</code>.</li></ul><h3 id="_5-throughput-under-sustained-mutation" tabindex="-1">#5 Throughput Under Sustained Mutation <a class="header-anchor" href="#_5-throughput-under-sustained-mutation" aria-label="Permalink to &quot;#5 Throughput Under Sustained Mutation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th style="text-align:right;">Value (ms)</th></tr></thead><tbody><tr><td>p50</td><td style="text-align:right;">0.0061</td></tr><tr><td>p95</td><td style="text-align:right;">0.0096</td></tr><tr><td>p99</td><td style="text-align:right;">0.0162</td></tr><tr><td>max</td><td style="text-align:right;">0.9394</td></tr></tbody></table><p>Windowed p95 drift: <code>-42.28%</code> (end window vs start window).</p><p>Interpretation:</p><ul><li>No upward drift under sustained updates.</li><li>Throughput remains stable as history grows.</li></ul><h3 id="_6-fan-out-sensitivity-curves" tabindex="-1">#6 Fan-Out Sensitivity Curves <a class="header-anchor" href="#_6-fan-out-sensitivity-curves" aria-label="Permalink to &quot;#6 Fan-Out Sensitivity Curves&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Fanout</th><th style="text-align:right;">k</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td style="text-align:right;">10</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0110</td><td style="text-align:right;">0.0192</td><td style="text-align:right;">0.1016</td></tr><tr><td style="text-align:right;">100</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0075</td><td style="text-align:right;">0.0140</td><td style="text-align:right;">0.0300</td></tr><tr><td style="text-align:right;">500</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0070</td><td style="text-align:right;">0.0101</td><td style="text-align:right;">0.0139</td></tr><tr><td style="text-align:right;">1000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0057</td><td style="text-align:right;">0.0097</td><td style="text-align:right;">0.0196</td></tr><tr><td style="text-align:right;">2500</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0052</td><td style="text-align:right;">0.0076</td><td style="text-align:right;">0.0120</td></tr><tr><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0046</td><td style="text-align:right;">0.0056</td><td style="text-align:right;">0.0081</td></tr></tbody></table><p>Interpretation:</p><ul><li><code>k</code> stays constant at <code>2</code>.</li><li>Latency stays in micro-to-low-millisecond range across fanout values.</li></ul><h3 id="_7-cold-vs-warm-runtime-profiles" tabindex="-1">#7 Cold vs Warm Runtime Profiles <a class="header-anchor" href="#_7-cold-vs-warm-runtime-profiles" aria-label="Permalink to &quot;#7 Cold vs Warm Runtime Profiles&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Nodes</th><th style="text-align:right;">Cold (ms)</th><th style="text-align:right;">Warm (ms)</th><th style="text-align:right;">Steady Avg (ms)</th><th style="text-align:right;">Steady Min (ms)</th><th style="text-align:right;">Steady Max (ms)</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">0.1846</td><td style="text-align:right;">0.0909</td><td style="text-align:right;">0.0229</td><td style="text-align:right;">0.0091</td><td style="text-align:right;">0.4603</td></tr><tr><td style="text-align:right;">1000</td><td style="text-align:right;">0.0078</td><td style="text-align:right;">0.0101</td><td style="text-align:right;">0.0056</td><td style="text-align:right;">0.0050</td><td style="text-align:right;">0.0108</td></tr><tr><td style="text-align:right;">5000</td><td style="text-align:right;">0.0116</td><td style="text-align:right;">0.0108</td><td style="text-align:right;">0.0059</td><td style="text-align:right;">0.0046</td><td style="text-align:right;">0.0132</td></tr></tbody></table><p>Interpretation:</p><ul><li>Cold penalty is isolated.</li><li>Warm/steady paths are consistently fast.</li></ul><h3 id="_8-explain-overhead-budget" tabindex="-1">#8 Explain Overhead Budget <a class="header-anchor" href="#_8-explain-overhead-budget" aria-label="Permalink to &quot;#8 Explain Overhead Budget&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td>baseline</td><td style="text-align:right;">0.0071</td><td style="text-align:right;">0.0139</td><td style="text-align:right;">0.0238</td></tr><tr><td>with_explain</td><td style="text-align:right;">0.0113</td><td style="text-align:right;">0.0173</td><td style="text-align:right;">0.0282</td></tr></tbody></table><p><code>p95</code> overhead: <code>24.92%</code>.</p><p>Interpretation:</p><ul><li><code>explain(path)</code> adds bounded overhead while preserving traceability.</li><li>Absolute overhead remains sub-millisecond, making it production-safe for real-time auditing.</li></ul><h3 id="_9-secret-scope-performance-impact" tabindex="-1">#9 Secret-Scope Performance Impact <a class="header-anchor" href="#_9-secret-scope-performance-impact" aria-label="Permalink to &quot;#9 Secret-Scope Performance Impact&quot;">​</a></h3><p>Repeated isolated runs on <code>April 9, 2026</code>:</p><table tabindex="0"><thead><tr><th>Scope</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td>public</td><td style="text-align:right;">0.0088 - 0.0095</td><td style="text-align:right;">0.0162 - 0.0170</td><td style="text-align:right;">0.0233 - 0.1565</td></tr><tr><td>secret</td><td style="text-align:right;">0.5785 - 0.6073</td><td style="text-align:right;">0.7475 - 0.8788</td><td style="text-align:right;">1.0762 - 1.5146</td></tr></tbody></table><p>Interpretation:</p><ul><li>Secret path remains slower than public by design cost: crypto, stealth boundary logic, and lazy refresh/write-back.</li><li>In absolute terms, secret <code>p95</code> is now consistently sub-millisecond in isolated local runs for this scenario.</li><li>Compared with the March 2026 historical baseline in <code>BASELINE-5-FINAL.md</code> (<code>4.6503ms</code> secret <code>p95</code>), the current local envelope is roughly <code>81% - 84%</code> lower in absolute <code>p95</code>.</li><li>Slowdown percentages still look dramatic because the public path is already extremely close to the timer floor.</li></ul><h3 id="_10-push-vs-pull-eager-vs-lazy" tabindex="-1">#10 Push vs Pull (Eager vs Lazy) <a class="header-anchor" href="#_10-push-vs-pull-eager-vs-lazy" aria-label="Permalink to &quot;#10 Push vs Pull (Eager vs Lazy)&quot;">​</a></h3><p>Selected row from the latest isolated run (<code>fanout = 5000</code>):</p><table tabindex="0"><thead><tr><th>Mode</th><th style="text-align:right;">Fanout</th><th style="text-align:right;">k</th><th style="text-align:right;">Mutation p95 (ms)</th><th style="text-align:right;">Read p95 (ms)</th></tr></thead><tbody><tr><td>eager</td><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0515</td><td style="text-align:right;">0.0478</td></tr><tr><td>lazy</td><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0038</td><td style="text-align:right;">0.0035</td></tr></tbody></table><p>Interpretation:</p><ul><li>Both modes remain low-latency in steady-state.</li><li><code>push</code> and <code>first-read-after-write</code> stay measurable as separate costs, which is the benchmark&#39;s main purpose.</li><li>Single-run outliers can appear at lower fanouts, so this benchmark is best read as a shape test rather than a one-number SLA.</li></ul><h3 id="_11-secret-push-vs-pull-shared-v3-key-cache-lazy-recompute" tabindex="-1">#11 Secret Push vs Pull (Shared v3 Key Cache + Lazy Recompute) <a class="header-anchor" href="#_11-secret-push-vs-pull-shared-v3-key-cache-lazy-recompute" aria-label="Permalink to &quot;#11 Secret Push vs Pull (Shared v3 Key Cache + Lazy Recompute)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plane</th><th style="text-align:right;">Nodes</th><th style="text-align:right;">Mutation p95 (ms)</th><th style="text-align:right;">Read p95 (ms)</th></tr></thead><tbody><tr><td>public</td><td style="text-align:right;">100</td><td style="text-align:right;">0.0173</td><td style="text-align:right;">0.0237</td></tr><tr><td>secret</td><td style="text-align:right;">100</td><td style="text-align:right;">0.0472</td><td style="text-align:right;">0.7461</td></tr><tr><td>public</td><td style="text-align:right;">300</td><td style="text-align:right;">0.0047</td><td style="text-align:right;">0.0047</td></tr><tr><td>secret</td><td style="text-align:right;">300</td><td style="text-align:right;">0.0408</td><td style="text-align:right;">0.3542</td></tr><tr><td>public</td><td style="text-align:right;">600</td><td style="text-align:right;">0.0042</td><td style="text-align:right;">0.0040</td></tr><tr><td>secret</td><td style="text-align:right;">600</td><td style="text-align:right;">0.0403</td><td style="text-align:right;">0.6410</td></tr></tbody></table><p>Slowdown ratios (secret/public p95):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Nodes</th><th style="text-align:right;">Mutation slowdown x</th><th style="text-align:right;">Read slowdown x</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">2.73x</td><td style="text-align:right;">31.48x</td></tr><tr><td style="text-align:right;">300</td><td style="text-align:right;">8.68x</td><td style="text-align:right;">75.36x</td></tr><tr><td style="text-align:right;">600</td><td style="text-align:right;">9.60x</td><td style="text-align:right;">160.25x</td></tr></tbody></table><p>Interpretation:</p><ul><li>Secret mutation cost stays in low-sub-millisecond territory.</li><li>Secret read cost is still the noisiest part of the runtime because this benchmark couples crypto with lazy derivation refresh and write-back.</li><li>In absolute terms, the latest isolated run still kept secret read <code>p95</code> below <code>1ms</code> at <code>100</code> and <code>600</code> nodes, and around <code>0.35ms</code> at <code>300</code> nodes.</li></ul><h2 id="regression-gate-status" tabindex="-1">Regression Gate Status <a class="header-anchor" href="#regression-gate-status" aria-label="Permalink to &quot;Regression Gate Status&quot;">​</a></h2><p>Latest gate output:</p><ul><li><code>latency_p95</code>: ✅ <code>0.0201ms</code> (threshold <code>20ms</code>)</li><li><code>complexity_k</code>: ✅ <code>k=2</code> (threshold <code>&lt;=4</code>)</li><li><code>stealth_masking</code>: ✅ <code>origin=stealth</code>, <code>masked=true</code>, <code>value=●●●●</code></li></ul><h2 id="what-is-proven-now" tabindex="-1">What Is Proven Now <a class="header-anchor" href="#what-is-proven-now" aria-label="Permalink to &quot;What Is Proven Now&quot;">​</a></h2><ul><li>Public-path performance is stable and effectively bounded by small <code>k</code>.</li><li>Lazy/eager recompute modes are operational and benchmarked.</li><li>Explainability overhead is measurable and bounded.</li><li>Secret-path cost is no longer monolithic; shared v3 key reuse removed the worst cold branch-derivation penalty.</li><li>Secret reads are still the most expensive path, but they now sit in the sub-millisecond envelope for the main <code>#9</code> scenario on isolated runs.</li><li>Privacy and semantic invariants remain intact while performance work lands.</li></ul><h2 id="next-optimization-frontier" tabindex="-1">Next Optimization Frontier <a class="header-anchor" href="#next-optimization-frontier" aria-label="Permalink to &quot;Next Optimization Frontier&quot;">​</a></h2><ul><li>If we chase the final secret-latency gap, the next real frontier is no longer &quot;more cache.&quot;</li><li>It is separating lazy derivation refresh from full memory append/hash-chain write-back on internal recomputes.</li><li>That is a semantic refactor, not just a micro-optimization, so it should be driven by product usage traces rather than benchmark vanity alone.</li></ul>',51)])])}const y=e(l,[["render",d]]);export{u as __pageData,y as default};
